"""Flask web application for serving A.U.R.O.R.A. orchestrator generated files.

This module provides a web interface to view and serve files generated by the
aurora_orchestrator. It dynamically serves frontend files from the PROJECT_STATE
codebase without requiring them to be written to disk.
"""
from __future__ import annotations

import json
import os
from flask import Flask, jsonify, render_template_string, Response
from typing import Dict, Optional

# Import aurora_orchestrator components
from aurora_orchestrator import (
    AuroraOrchestrator,
    PROJECT_STATE,
    CONFIG,
    SimulationSettings,
    persist_final_state,
)


