@app.route('/')
def dashboard():
    """Render the main dashboard showing project state and generated files."""
    stats = {
        'completed': len(PROJECT_STATE['tasks']['completed']),
        'in_progress': len(PROJECT_STATE['tasks']['in_progress']),
        'files': len(PROJECT_STATE['codebase']['files']),
        'messages': len(PROJECT_STATE['message_bus']),
    }
    
    return render_template_string(
        DASHBOARD_TEMPLATE,
        config=CONFIG,
        stats=stats,
        files=list(PROJECT_STATE['codebase']['files'].keys()),
        design_system=PROJECT_STATE['design_system'],
        messages=PROJECT_STATE['message_bus'],
        last_update=PROJECT_STATE.get('last_update'),
    )


@app.route('/files/<path:file_path>')
def view_file(file_path: str):
    """View a specific file from the generated codebase."""
    content = PROJECT_STATE['codebase']['files'].get(file_path)
    
    if content is None:
        return jsonify({
            'error': 'File not found',
            'file_path': file_path,
            'available_files': list(PROJECT_STATE['codebase']['files'].keys())
        }), 404
    
    return render_template_string(
        FILE_VIEWER_TEMPLATE,
        file_path=file_path,
        content=content,
    )


@app.route('/api/state')
def api_state():
    """Return the complete project state as JSON."""
    return jsonify(PROJECT_STATE)


@app.route('/api/files')
def api_files():
    """Return a list of all generated files with their content."""
    return jsonify({
        'files': PROJECT_STATE['codebase']['files'],
        'count': len(PROJECT_STATE['codebase']['files']),
    })


@app.route('/api/run-orchestrator', methods=['POST'])
def run_orchestrator():
    """Run the aurora orchestrator to generate new files."""
    try:
        # Initialize orchestrator with faster settings for web usage
        settings = SimulationSettings()
        settings.api_latency_seconds = 0.5  # Faster for web
        settings.loop_pause_seconds = 0.5
        
        orchestrator = AuroraOrchestrator(settings)
        orchestrator.generate_initial_tasks()
        orchestrator.main_loop()
        persist_final_state()
        
        return jsonify({
            'success': True,
            'message': 'Orchestrator completed successfully',
            'stats': {
                'completed': len(PROJECT_STATE['tasks']['completed']),
                'files': len(PROJECT_STATE['codebase']['files']),
                'messages': len(PROJECT_STATE['message_bus']),
            }
        })
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


def main(host: str = '0.0.0.0', port: int = 5000, debug: bool = False) -> None:
    """Start the Flask web server.
    
    Args:
        host: Host address to bind to (default: 0.0.0.0)
        port: Port number to listen on (default: 5000)
        debug: Enable debug mode (default: False)
    """
    print("\n" + "=" * 70)
    print("🚀 A.U.R.O.R.A. Flask Web Server")
    print("=" * 70)
    print(f"Server starting on http://{host}:{port}")
    print("\nAvailable endpoints:")
    print(f"  • Dashboard:    http://localhost:{port}/")
    print(f"  • API State:    http://localhost:{port}/api/state")
    print(f"  • API Files:    http://localhost:{port}/api/files")
    print(f"  • View File:    http://localhost:{port}/files/<path>")
    print("\nPress Ctrl+C to stop the server")
    print("=" * 70 + "\n")
    
    app.run(host=host, port=port, debug=debug)


if __name__ == '__main__':
    # Check if orchestrator has been run, if not run it first
    if not PROJECT_STATE['codebase']['files']:
        print("No files in PROJECT_STATE. Running orchestrator first...")
        orchestrator = AuroraOrchestrator()
        orchestrator.generate_initial_tasks()
        orchestrator.main_loop()
        persist_final_state()
        print("\nOrchestrator completed. Starting web server...\n")
    
    # Start the Flask server
    main(
        host=os.getenv('FLASK_HOST', '0.0.0.0'),
        port=int(os.getenv('FLASK_PORT', 5000)),
        debug=os.getenv('FLASK_DEBUG', 'False').lower() == 'true',
    )
